t = int(input())
for _ in range(t):
    s = input().strip()
    if s == "abc":
        print("YES")
    else:
        # Check if swapping any two characters makes it "abc"
        for i in range(3):
            for j in range(i + 1, 3):
                lst = list(s)
                lst[i], lst[j] = lst[j], lst[i]
                if ''.join(lst) == "abc":
                    print("YES")
                    break
            else:
                continue
            break
        else:
            print("NO")
